import React, { useState, useCallback, useEffect } from 'react';
import { Source, ActiveView, UserTier, RevisionPlan, Flashcard, QuizQuestion, SearchMessage, ExamBoard, SearchStatus, Theme } from './types';
import LeftSidebar from './components/LeftSidebar';
import SourceViewer from './components/SourceViewer';
import RevisionPlanner from './components/RevisionPlanner';
import FlashcardViewer from './components/FlashcardViewer';
import QuizRunner from './components/QuizRunner';
import ChatPanel from './components/ChatPanel';
import TierModal from './components/TierModal';
import AiSearch from './components/AiSearch';
import AuthPage from './components/AuthPage';
import CheckoutPage from './components/CheckoutPage';
import SettingsModal from './components/SettingsModal';
import { generateRevisionPlan, generateFlashcards, generateQuiz, searchWithAi } from './services/geminiService';
import { TrustedSource } from './types';
import { sampleSources } from './data/sampleSources';
import UpgradeToProPanel from './components/UpgradeToProPanel';

const MAX_FREE_SEARCHES = 15;

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => !!localStorage.getItem('user-authenticated'));
  const [sources, setSources] = useState<Source[]>(() => {
    return sampleSources;
  });
  const [selectedSource, setSelectedSource] = useState<Source | null>(sampleSources[0] || null);
  const [activeView, setActiveView] = useState<ActiveView>('source');

  const [revisionPlan, setRevisionPlan] = useState<RevisionPlan | null>(null);
  const [flashcards, setFlashcards] = useState<Flashcard[]>([]);
  const [quiz, setQuiz] = useState<QuizQuestion[]>([]);
  const [searchHistory, setSearchHistory] = useState<SearchMessage[]>([]);

  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [loadingMessage, setLoadingMessage] = useState<string>('');

  const [userTier, setUserTier] = useState<UserTier>(() => (localStorage.getItem('user-tier') as UserTier) || 'free');
  const [showTierModal, setShowTierModal] = useState<boolean>(false);
  const [showCheckout, setShowCheckout] = useState<boolean>(false);
  const [showAuthModal, setShowAuthModal] = useState<boolean>(false);
  const [showSettingsModal, setShowSettingsModal] = useState<boolean>(false);

  const [searchStatus, setSearchStatus] = useState<SearchStatus>(() => {
    const saved = localStorage.getItem('search-status');
    const today = new Date().toLocaleDateString('en-CA'); // YYYY-MM-DD
    if (saved) {
      const parsed = JSON.parse(saved) as SearchStatus;
      if (parsed.lastDate === today) return parsed;
    }
    return { count: 0, lastDate: today };
  });

  const [theme, setTheme] = useState<Theme>(() => {
    return (localStorage.getItem('theme') as Theme) || 'dark';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark' || theme === 'oled') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    localStorage.setItem('theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('user-tier', userTier);
  }, [userTier]);

  useEffect(() => {
    localStorage.setItem('search-status', JSON.stringify(searchStatus));
  }, [searchStatus]);

  const handleLoginSuccess = () => {
    setIsAuthenticated(true);
    localStorage.setItem('user-authenticated', 'true');
    setShowAuthModal(false);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUserTier('free');
    setSources(sampleSources);
    setSelectedSource(sampleSources[0] || null);
    setActiveView('source');
    localStorage.removeItem('user-authenticated');
    localStorage.removeItem('user-tier');
    localStorage.removeItem('subscription-key');
  };

  const handleUpgradeInitiate = () => {
    if (!isAuthenticated) {
      setShowAuthModal(true);
      return;
    }
    setShowTierModal(false);
    setShowCheckout(true);
  };

  const handlePaymentSuccess = (key: string) => {
      setUserTier('premium');
      localStorage.setItem('subscription-key', key);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    if (!isAuthenticated) {
      setShowAuthModal(true);
      return;
    }
    const file = event.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (e) => {
        const newSource: Source = {
          id: Date.now().toString(),
          name: file.name,
          content: e.target?.result as string,
        };
        setSources(prev => [...prev, newSource]);
        setSelectedSource(newSource);
        handleSetActiveView('source');
      };
      reader.readAsText(file);
    }
  };

  const handleSelectSource = (source: Source) => {
    setSelectedSource(source);
    handleSetActiveView('source');
  };

  const handleDeleteSource = (sourceId: string) => {
    if (selectedSource?.id === sourceId) {
      setSelectedSource(sampleSources[0] || null);
      setActiveView('source');
    }
    setSources(prevSources => prevSources.filter(source => source.id !== sourceId));
  };


  const handleSetActiveView = (view: ActiveView) => {
    setRevisionPlan(null);
    setFlashcards([]);
    setQuiz([]);
    if (view !== 'search') {
      setSearchHistory([]);
    }
    setActiveView(view);
  };

  const handleGenerateRevisionPlan = useCallback(async () => {
    if (!selectedSource) return;
    if(isAuthenticated && userTier === 'free' && sources.filter(s => !s.id.startsWith('sample-')).length >= 1) {
        setShowTierModal(true);
        return;
    }
    setIsLoading(true);
    setLoadingMessage('Crafting your revision plan...');
    try {
      const plan = await generateRevisionPlan(selectedSource.content);
      setRevisionPlan(plan);
    } catch (error) {
      console.error("Failed to generate revision plan:", error);
      alert("Sorry, I couldn't generate a revision plan. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier, sources, isAuthenticated]);

  const handleGenerateFlashcards = useCallback(async () => {
    if (!selectedSource) return;
    setIsLoading(true);
    setLoadingMessage('Creating your flashcards...');
    try {
      const cards = await generateFlashcards(selectedSource.content);
      setFlashcards(cards);
    } catch (error) {
      console.error("Failed to generate flashcards:", error);
      alert("Sorry, I couldn't generate flashcards. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource]);

  const handleGenerateQuiz = useCallback(async (questionCount: number) => {
    if (!selectedSource) return;
    if (isAuthenticated && userTier === 'free' && questionCount > 5) {
      setShowTierModal(true);
      return;
    }
    setIsLoading(true);
    setLoadingMessage('Building your quiz...');
    try {
      const questions = await generateQuiz(selectedSource.content, questionCount);
      setQuiz(questions);
    } catch (error) {
      console.error("Failed to generate quiz:", error);
      alert("Sorry, I couldn't generate a quiz. Please try again.");
    } finally {
      setIsLoading(false);
    }
  }, [selectedSource, userTier, isAuthenticated]);

  const handleAiSearch = useCallback(async (query: string, trustedSources: TrustedSource[], examBoards: ExamBoard[]) => {
    const today = new Date().toLocaleDateString('en-CA');

    if (userTier === 'free') {
      if (searchStatus.lastDate === today && searchStatus.count >= MAX_FREE_SEARCHES) {
        setShowTierModal(true);
        return;
      }
    }

    const userMessage: SearchMessage = { sender: 'user', text: query };
    const currentHistory = [...searchHistory, userMessage];
    setSearchHistory(currentHistory);
    setIsLoading(true);
    setLoadingMessage('Searching with Gemini...');
    try {
      const result = await searchWithAi(currentHistory, trustedSources, examBoards);
      const aiMessage: SearchMessage = { sender: 'ai', text: result.summary, sources: result.sources };
      setSearchHistory(prev => [...prev, aiMessage]);

      if (userTier === 'free') {
        setSearchStatus(prev => ({
          count: prev.lastDate === today ? prev.count + 1 : 1,
          lastDate: today
        }));
      }
    } catch (error) {
      console.error("Failed to perform AI search:", error);
      const errorMessage: SearchMessage = { sender: 'ai', text: "Sorry, I couldn't complete the search. Please try again."};
      setSearchHistory(prev => [...prev, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  }, [userTier, searchStatus, searchHistory]);

  const renderMainContent = () => {
    if (isLoading && activeView !== 'search') {
      return (
        <div className="flex flex-col items-center justify-center h-full text-gray-500 dark:text-gray-400">
          <svg className="animate-spin h-10 w-10 text-indigo-500 dark:text-indigo-400 mb-4" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <p className="text-lg">{loadingMessage}</p>
        </div>
      );
    }

    if (activeView !== 'search' && !selectedSource) {
      return (
        <div className="flex items-center justify-center h-full text-gray-600 dark:text-gray-500">
          <p className="text-xl">Select or upload a source document to get started.</p>
        </div>
      );
    }

    switch (activeView) {
      case 'plan':
        return <RevisionPlanner plan={revisionPlan} onGenerate={handleGenerateRevisionPlan} theme={theme} />;
      case 'flashcards':
        return <FlashcardViewer cards={flashcards} onGenerate={handleGenerateFlashcards} theme={theme} />;
      case 'quiz':
        return <QuizRunner quiz={quiz} onGenerate={handleGenerateQuiz} userTier={userTier} isAuthenticated={isAuthenticated} theme={theme} />;
      case 'search':
        return <AiSearch onSearch={handleAiSearch} searchHistory={searchHistory} isLoading={isLoading} userTier={userTier} searchCount={searchStatus.count} maxSearches={MAX_FREE_SEARCHES} theme={theme} />;
      case 'source':
      default:
        return selectedSource ? <SourceViewer source={selectedSource} theme={theme} /> : null;
    }
  };

  return (
    <div className={`flex h-screen text-gray-800 dark:text-gray-100 font-sans transition-colors duration-300 ${theme === 'oled' ? 'bg-black' : 'bg-gray-100 dark:bg-gray-900'}`}>
      {showAuthModal && <AuthPage onLoginSuccess={handleLoginSuccess} onClose={() => setShowAuthModal(false)} theme={theme} />}
      {showTierModal && <TierModal onClose={() => setShowTierModal(false)} onUpgrade={handleUpgradeInitiate} theme={theme} />}
      {showCheckout && <CheckoutPage onClose={() => setShowCheckout(false)} onPaymentSuccess={handlePaymentSuccess} theme={theme} />}
      {showSettingsModal && <SettingsModal onClose={() => setShowSettingsModal(false)} currentTheme={theme} setTheme={setTheme} />}

      <LeftSidebar
        sources={sources}
        onFileUpload={handleFileUpload}
        onSelectSource={handleSelectSource}
        onDeleteSource={handleDeleteSource}
        selectedSource={selectedSource}
        activeView={activeView}
        setActiveView={handleSetActiveView}
        userTier={userTier}
        onUpgradeClick={() => setShowTierModal(true)}
        theme={theme}
        onOpenSettings={() => setShowSettingsModal(true)}
        isAuthenticated={isAuthenticated}
        onLoginClick={() => setShowAuthModal(true)}
        onLogout={handleLogout}
        searchCount={searchStatus.count}
        maxSearches={MAX_FREE_SEARCHES}
      />
      <main className="flex-grow flex flex-col md:grid md:grid-cols-3 gap-4 p-4 h-screen overflow-hidden">
        <div className={`md:col-span-2 rounded-lg shadow-lg overflow-y-auto h-full p-2 md:p-6 transition-colors duration-300 scrollbar-custom ${theme === 'oled' ? 'bg-black border border-gray-800' : 'bg-white dark:bg-gray-800'}`}>
          <div key={activeView} className="animate-fade-in h-full">
            {renderMainContent()}
          </div>
        </div>
        <div className={`rounded-lg shadow-lg flex flex-col h-full overflow-hidden transition-colors duration-300 ${theme === 'oled' ? 'bg-black border border-gray-800' : 'bg-white dark:bg-gray-800'}`}>
          {userTier === 'premium' ? (
            <ChatPanel selectedSource={selectedSource} isAuthenticated={isAuthenticated} theme={theme} />
          ) : (
            <UpgradeToProPanel onUpgradeClick={() => setShowTierModal(true)} theme={theme} />
          )}
        </div>
      </main>
    </div>
  );
}

import React from 'react';
// Fix: Add theme prop to props interface to fix TypeScript error from App.tsx.
import { RevisionPlan, Theme } from '../types';

interface RevisionPlannerProps {
  plan: RevisionPlan | null;
  onGenerate: () => void;
  theme: Theme;
}

export default function RevisionPlanner({ plan, onGenerate }: RevisionPlannerProps) {
  if (!plan) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center">
        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-4">Ready to plan your revision?</h2>
        <p className="text-gray-500 dark:text-gray-400 mb-6">Let AI create a structured study plan from your source material.</p>
        <button
          onClick={onGenerate}
          className="px-6 py-3 bg-indigo-600 text-white font-semibold rounded-lg hover:bg-indigo-700 transition-transform transform hover:scale-105"
        >
          Generate Revision Plan
        </button>
      </div>
    );
  }

  return (
    <div>
      <h2 className="text-3xl font-bold text-gray-900 dark:text-white mb-6">Your Revision Plan</h2>
      <div className="space-y-6">
        {plan.map((item, index) => (
          <div key={index} className="bg-gray-100 dark:bg-gray-700 p-6 rounded-lg">
            <h3 className="text-xl font-semibold text-indigo-600 dark:text-indigo-300 mb-3">{index + 1}. {item.topic}</h3>
            <ul className="space-y-2 list-disc list-inside">
              {item.subtopics.map((subtopic, subIndex) => (
                <li key={subIndex} className="text-gray-700 dark:text-gray-300 ml-4">
                  {subtopic}
                </li>
              ))}
            </ul>
          </div>
        ))}
      </div>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
// Fix: Add theme prop to props interface to fix TypeScript error from App.tsx.
import { Flashcard, Theme } from '../types';

interface FlashcardViewerProps {
  cards: Flashcard[];
  onGenerate: () => void;
  theme: Theme;
}

export default function FlashcardViewer({ cards, onGenerate }: FlashcardViewerProps) {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);

  useEffect(() => {
    setCurrentIndex(0);
    setIsFlipped(false);
  }, [cards]);

  if (cards.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center">
        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-4">Test your knowledge.</h2>
        <p className="text-gray-500 dark:text-gray-400 mb-6">Generate interactive flashcards from your source material.</p>
        <button
          onClick={onGenerate}
          className="px-6 py-3 bg-indigo-600 text-white font-semibold rounded-lg hover:bg-indigo-700 transition-transform transform hover:scale-105"
        >
          Generate Flashcards
        </button>
      </div>
    );
  }

  const currentCard = cards[currentIndex];

  const handleNext = () => {
    setIsFlipped(false);
    setCurrentIndex((prev) => (prev + 1) % cards.length);
  };

  const handlePrev = () => {
    setIsFlipped(false);
    setCurrentIndex((prev) => (prev - 1 + cards.length) % cards.length);
  };

  return (
    <div className="flex flex-col items-center justify-center h-full">
      <h2 className="text-3xl font-bold text-gray-900 dark:text-white mb-6">Flashcards</h2>
      <div className="w-full max-w-2xl h-80 perspective-1000">
        <div
          className={`relative w-full h-full transform-style-preserve-3d transition-transform duration-700 ${isFlipped ? 'rotate-y-180' : ''}`}
          onClick={() => setIsFlipped(!isFlipped)}
        >
          <div className="absolute w-full h-full backface-hidden flex items-center justify-center p-6 bg-gray-200 dark:bg-gray-700 rounded-xl shadow-2xl cursor-pointer">
            <p className="text-2xl text-center text-gray-900 dark:text-white">{currentCard.term}</p>
          </div>
          <div className="absolute w-full h-full backface-hidden flex items-center justify-center p-6 bg-indigo-600 rounded-xl shadow-2xl cursor-pointer transform rotate-y-180">
            <p className="text-xl text-center text-white">{currentCard.definition}</p>
          </div>
        </div>
      </div>
      <p className="mt-4 text-gray-500 dark:text-gray-400">{currentIndex + 1} / {cards.length}</p>
      <div className="mt-6 flex items-center space-x-4">
        <button onClick={handlePrev} className="px-5 py-2 bg-gray-300 dark:bg-gray-600 rounded-lg hover:bg-gray-400 dark:hover:bg-gray-500 transition-colors">Previous</button>
        <button onClick={() => setIsFlipped(!isFlipped)} className="px-8 py-3 bg-gray-200 dark:bg-gray-700 rounded-lg font-bold hover:bg-gray-300 dark:hover:bg-gray-600 transition-colors">Flip</button>
        <button onClick={handleNext} className="px-5 py-2 bg-gray-300 dark:bg-gray-600 rounded-lg hover:bg-gray-400 dark:hover:bg-gray-500 transition-colors">Next</button>
      </div>
    </div>
  );
}

// Basic CSS for 3D effect (Tailwind doesn't have utilities for this out of the box)
const style = document.createElement('style');
style.innerHTML = `
  .perspective-1000 { perspective: 1000px; }
  .transform-style-preserve-3d { transform-style: preserve-3d; }
  .backface-hidden { backface-visibility: hidden; -webkit-backface-visibility: hidden; }
  .rotate-y-180 { transform: rotateY(180deg); }
`;
document.head.appendChild(style);

import React, { useState, useEffect } from 'react';
// Fix: Add theme prop to props interface to fix TypeScript error from App.tsx.
import { QuizQuestion, UserTier, Theme } from '../types';

interface QuizRunnerProps {
  quiz: QuizQuestion[];
  onGenerate: (questionCount: number) => void;
  userTier: UserTier;
  isAuthenticated: boolean;
  theme: Theme;
}

export default function QuizRunner({ quiz, onGenerate, userTier, isAuthenticated }: QuizRunnerProps) {
  const [questionCount, setQuestionCount] = useState(5);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedAnswers, setSelectedAnswers] = useState<{[key: number]: string}>({});
  const [isFinished, setIsFinished] = useState(false);
  const [score, setScore] = useState(0);

  useEffect(() => {
    setCurrentIndex(0);
    setSelectedAnswers({});
    setIsFinished(false);
    setScore(0);
  }, [quiz]);

  const handleAnswerSelect = (option: string) => {
    if (isFinished) return;
    setSelectedAnswers(prev => ({ ...prev, [currentIndex]: option }));
  };

  const handleNext = () => {
    if (currentIndex < quiz.length - 1) {
      setCurrentIndex(prev => prev + 1);
    } else {
      // Finish quiz
      let finalScore = 0;
      quiz.forEach((q, index) => {
        if (selectedAnswers[index] === q.correctAnswer) {
          finalScore++;
        }
      });
      setScore(finalScore);
      setIsFinished(true);
    }
  };

  if (quiz.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center h-full text-center">
        <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-4">Challenge yourself with a quiz.</h2>
        <p className="text-gray-500 dark:text-gray-400 mb-6">Generate a multiple-choice quiz based on your study material.</p>
        <div className="flex items-center space-x-4">
          <label htmlFor="question-count" className="text-gray-600 dark:text-gray-300">Questions:</label>
          <select 
            id="question-count"
            value={questionCount}
            onChange={(e) => setQuestionCount(Number(e.target.value))}
            className="bg-gray-200 dark:bg-gray-700 text-gray-900 dark:text-white rounded-md p-2"
          >
            <option value={5}>5</option>
            <option value={10}>10 {isAuthenticated && userTier === 'free' && '(Premium)'}</option>
            <option value={15}>15 {isAuthenticated && userTier === 'free' && '(Premium)'}</option>
          </select>
        </div>
        <button
          onClick={() => onGenerate(questionCount)}
          className="mt-6 px-6 py-3 bg-indigo-600 text-white font-semibold rounded-lg hover:bg-indigo-700 transition-transform transform hover:scale-105"
        >
          Generate Quiz
        </button>
      </div>
    );
  }

  if (isFinished) {
    return (
        <div className="flex flex-col items-center justify-center h-full text-center">
            <h2 className="text-4xl font-bold text-gray-900 dark:text-white mb-4">Quiz Complete!</h2>
            <p className="text-2xl text-indigo-500 dark:text-indigo-400 mb-8">Your Score: {score} / {quiz.length}</p>
            <button
                onClick={() => onGenerate(quiz.length)}
                className="px-6 py-3 bg-indigo-600 text-white font-semibold rounded-lg hover:bg-indigo-700"
            >
                Try Again
            </button>
        </div>
    );
  }

  const currentQuestion = quiz[currentIndex];

  return (
    <div className="p-4">
        <p className="text-sm text-gray-500 dark:text-gray-400 mb-2">Question {currentIndex + 1} of {quiz.length}</p>
        <h3 className="text-2xl font-semibold text-gray-900 dark:text-white mb-6">{currentQuestion.question}</h3>
        <div className="space-y-3">
            {currentQuestion.options.map((option, index) => {
                const isSelected = selectedAnswers[currentIndex] === option;
                return (
                    <button
                        key={index}
                        onClick={() => handleAnswerSelect(option)}
                        className={`w-full text-left p-4 rounded-lg border-2 transition-colors duration-200 ${
                            isSelected
                                ? 'bg-indigo-500 border-indigo-400 text-white'
                                : 'bg-gray-100 dark:bg-gray-700 border-gray-300 dark:border-gray-600 hover:bg-gray-200 dark:hover:bg-gray-600'
                        }`}
                    >
                        {option}
                    </button>
                );
            })}
        </div>
        <div className="mt-8 flex justify-end">
            <button
                onClick={handleNext}
                disabled={!selectedAnswers[currentIndex]}
                className="px-8 py-3 bg-indigo-600 text-white font-semibold rounded-lg hover:bg-indigo-700 disabled:bg-gray-400 dark:disabled:bg-gray-500 disabled:cursor-not-allowed"
            >
                {currentIndex < quiz.length - 1 ? 'Next' : 'Finish'}
            </button>
        </div>
    </div>
  );
}

import React from 'react';
import { Source, ActiveView, UserTier, Theme } from '../types';

interface LeftSidebarProps {
  sources: Source[];
  onFileUpload: (event: React.ChangeEvent<HTMLInputElement>) => void;
  onSelectSource: (source: Source) => void;
  onDeleteSource: (sourceId: string) => void;
  selectedSource: Source | null;
  activeView: ActiveView;
  setActiveView: (view: ActiveView) => void;
  userTier: UserTier;
  onUpgradeClick: () => void;
  theme: Theme;
  onOpenSettings: () => void;
  isAuthenticated: boolean;
  onLoginClick: () => void;
  onLogout: () => void;
  searchCount: number;
  maxSearches: number;
}

const NavItem: React.FC<{
  icon: React.ReactElement;
  label: string;
  isActive: boolean;
  onClick: () => void;
  disabled?: boolean;
  isPremium?: boolean;
}> = ({ icon, label, isActive, onClick, disabled, isPremium = false }) => (
  <button
    onClick={onClick}
    disabled={disabled}
    className={`flex items-center w-full px-4 py-3 text-sm font-medium rounded-lg transition-all duration-300 ${
      isActive
        ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-600/30'
        : 'text-gray-500 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 hover:text-gray-900 dark:hover:text-white'
    } ${disabled ? 'opacity-50 cursor-not-allowed' : ''}`}
  >
    {icon}
    <span className="ml-3 flex-grow text-left">{label}</span>
    {isPremium && <span className="text-[10px] font-extrabold text-yellow-600 dark:text-yellow-400 bg-yellow-100 dark:bg-yellow-900/40 px-2 py-0.5 rounded-full border border-yellow-200 dark:border-yellow-700/50">PRO</span>}
  </button>
);

export default function LeftSidebar({
  sources,
  onFileUpload,
  onSelectSource,
  onDeleteSource,
  selectedSource,
  activeView,
  setActiveView,
  userTier,
  onUpgradeClick,
  theme,
  onOpenSettings,
  isAuthenticated,
  onLoginClick,
  onLogout,
  searchCount,
  maxSearches,
}: LeftSidebarProps) {

  const handleSearchClick = () => {
    setActiveView('search');
  };

  const handleAddSourceClick = (event: React.MouseEvent<HTMLLabelElement>) => {
    if (!isAuthenticated) {
      event.preventDefault();
      onLoginClick();
    }
  };

  const handleDeleteClick = (e: React.MouseEvent, source: Source) => {
    e.stopPropagation();
    if (window.confirm(`Are you sure you want to delete "${source.name}"?`)) {
        onDeleteSource(source.id);
    }
  };

  const searchPercentage = Math.min(100, (searchCount / maxSearches) * 100);

  return (
    <aside className={`w-80 p-4 flex flex-col h-full border-r shadow-xl z-20 transition-colors duration-300 ${theme === 'oled' ? 'bg-black border-gray-800' : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700'}`}>
      <div className="flex items-center mb-6">
        <img src="/logo.svg" alt="StudyLM Logo" className="w-8 h-8" />
        <div className="ml-2">
          <h1 className="text-xl font-bold text-gray-900 dark:text-white">StudyLM</h1>
          <p className="text-[10px] text-gray-500 dark:text-gray-400 -mt-1">Powered by Google Gemini</p>
        </div>
      </div>

      <div className="mb-4">
        <label
          htmlFor="file-upload"
          onClick={handleAddSourceClick}
          className="w-full text-center px-4 py-2 bg-indigo-600 text-white rounded-md cursor-pointer hover:bg-indigo-700 transition-all duration-200 block font-semibold shadow-md active:scale-95"
        >
          + Add Source
        </label>
        <input id="file-upload" type="file" className="hidden" onChange={onFileUpload} accept=".txt,.md" />
      </div>

      <div className="flex-grow overflow-y-auto pr-2 -mr-2 scrollbar-custom">
        <h2 className="text-[10px] font-bold text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-3 px-2">Knowledge Base</h2>
        <ul className="space-y-1">
          {sources.map(source => (
            <li key={source.id} className="group relative flex items-center">
              <button
                onClick={() => onSelectSource(source)}
                className={`flex-grow text-left px-3 py-2.5 rounded-md text-sm transition-all duration-200 truncate ${
                  selectedSource?.id === source.id ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-600 dark:text-indigo-300 font-bold border-l-4 border-indigo-500' : 'text-gray-600 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 border-l-4 border-transparent'
                }`}
              >
                {source.name}
              </button>
              {!source.id.startsWith('sample-') && (
                <button 
                  onClick={(e) => handleDeleteClick(e, source)}
                  className="absolute right-2 top-1/2 -translate-y-1/2 p-1.5 rounded-full text-gray-400 hover:bg-red-500 hover:text-white opacity-0 group-hover:opacity-100 transition-all focus:opacity-100"
                  aria-label={`Delete ${source.name}`}
                >
                  <TrashIcon/>
                </button>
              )}
            </li>
          ))}
        </ul>
      </div>

      <div className={`mt-auto border-t pt-4 transition-colors duration-300 ${theme === 'oled' ? 'border-gray-800' : 'border-gray-100 dark:border-gray-700'}`}>
        <div className={`rounded-xl p-2 border transition-colors duration-300 ${theme === 'oled' ? 'bg-black border-gray-800' : 'bg-gray-50 dark:bg-gray-700/20 border-gray-100 dark:border-gray-700'}`}>
          <h2 className="text-[10px] font-bold text-gray-400 dark:text-gray-500 uppercase tracking-widest mb-2 px-2">Learning Tools</h2>
          <nav className="space-y-1">
              <NavItem icon={<SearchIcon />} label="AI Search" isActive={activeView === 'search'} onClick={handleSearchClick} isPremium={userTier === 'free'} />
              <NavItem icon={<DocIcon />} label="View Source" isActive={activeView === 'source'} onClick={() => setActiveView('source')} disabled={!selectedSource} />
              <NavItem icon={<PlanIcon />} label="Revision Plan" isActive={activeView === 'plan'} onClick={() => setActiveView('plan')} disabled={!selectedSource} />
              <NavItem icon={<FlashcardIcon />} label="Flashcards" isActive={activeView === 'flashcards'} onClick={() => setActiveView('flashcards')} disabled={!selectedSource} />
              <NavItem icon={<QuizIcon />} label="AI Quiz" isActive={activeView === 'quiz'} onClick={() => setActiveView('quiz')} disabled={!selectedSource} />
          </nav>
        </div>

        <div className="mt-4 pt-4 space-y-4">
            {isAuthenticated && (
              <div className={`rounded-xl p-4 border shadow-inner transition-colors duration-300 ${theme === 'oled' ? 'bg-black border-gray-800' : 'bg-gray-50 dark:bg-gray-900/40 border-gray-100 dark:border-gray-700'}`}>
                  <div className="flex justify-between items-center mb-2">
                    <span className="text-xs font-bold text-gray-400 dark:text-gray-500 uppercase">Usage Plan</span>
                    <span className={`text-[10px] font-extrabold px-2 py-0.5 rounded-full ${userTier === 'premium' ? 'bg-yellow-100 dark:bg-yellow-900 text-yellow-700 dark:text-yellow-400' : 'bg-gray-200 dark:bg-gray-700 text-gray-600 dark:text-gray-400'}`}>
                        {userTier.toUpperCase()}
                    </span>
                  </div>

                  {userTier === 'free' && (
                    <div className="space-y-2">
                        <div className="flex justify-between text-[11px] text-gray-500 dark:text-gray-400">
                            <span>Daily AI Searches</span>
                            <span className="font-bold">{searchCount} / {maxSearches}</span>
                        </div>
                        <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-1.5">
                            <div 
                                className={`h-1.5 rounded-full transition-all duration-1000 ${searchCount >= maxSearches ? 'bg-red-500' : 'bg-indigo-500'}`} 
                                style={{ width: `${searchPercentage}%` }}
                            ></div>
                        </div>
                        <button onClick={onUpgradeClick} className="mt-3 w-full text-xs bg-gradient-to-r from-yellow-400 to-yellow-600 text-white font-black py-2 rounded-lg hover:brightness-110 transition-all shadow-md active:scale-95">
                            UPGRADE TO PRO
                        </button>
                    </div>
                  )}
                  {userTier === 'premium' && (
                      <p className="text-xs text-green-600 dark:text-green-400 font-bold flex items-center mt-1">
                          <svg className="w-4 h-4 mr-1" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm3.707-9.293a1 1 0 00-1.414-1.414L9 10.586 7.707 9.293a1 1 0 00-1.414 1.414l2 2a1 1 0 001.414 0l4-4z" clipRule="evenodd"></path></svg>
                          Unlimited Search Active
                      </p>
                  )}
              </div>
            )}

            <div className="flex items-center justify-between gap-2">
                {isAuthenticated ? (
                  <button onClick={onLogout} className="flex-grow flex items-center justify-center text-sm text-gray-400 hover:text-red-500 font-bold transition-colors py-2 px-3 border border-transparent hover:border-red-100 dark:hover:border-red-900/30 rounded-lg">
                      <LogoutIcon />
                      <span className="ml-2">Logout</span>
                  </button>
                ) : (
                  <button onClick={onLoginClick} className="flex-grow flex items-center justify-center text-sm text-white bg-indigo-600 hover:bg-indigo-700 font-bold transition-all py-2 px-4 rounded-lg shadow-lg active:scale-95">
                      <LoginIcon />
                      <span className="ml-2">Sign In</span>
                  </button>
                )}
                <button onClick={onOpenSettings} className={`p-2.5 rounded-lg text-gray-400 dark:text-gray-500 hover:bg-gray-100 dark:hover:bg-gray-700 border transition-all active:scale-90 ${theme === 'oled' ? 'border-gray-800' : 'border-gray-100 dark:border-gray-700'}`}>
                    <SettingsIcon />
                </button>
            </div>
        </div>
      </div>
    </aside>
  );
}

